/**
 * Project Routes - Workspace
 *
 * HTTP endpoints for workspace and project list management.
 */

import { Router, Request, Response } from 'express'
import { Workspace } from '../../types.js'
import { getServices } from '../../app.js'
import { sendResponse, sendError } from './helpers.js'

const router = Router()

/**
 * GET /api/projects
 * Get the full workspace including all projects
 *
 * Returns: Workspace
 */
router.get('/', async (_req: Request, res: Response) => {
  try {
    const services = getServices()

    if (!services.getWorkspace) {
      return sendError(res, 503, 'Workspace service not available')
    }

    const workspace: Workspace = await services.getWorkspace()

    sendResponse(res, 200, {
      success: true,
      data: workspace,
      timestamp: Date.now()
    })
  } catch (error: any) {
    console.error('[Projects Route] Get workspace error:', error)
    sendError(res, 500, error.message || 'Failed to get workspace')
  }
})

/**
 * PUT /api/projects
 * Save the full workspace
 *
 * Body: Workspace
 */
router.put('/', async (req: Request, res: Response) => {
  try {
    const services = getServices()

    if (!services.saveWorkspace) {
      return sendError(res, 503, 'Workspace service not available')
    }

    const workspace: Workspace = req.body

    if (!workspace || !Array.isArray(workspace.projects)) {
      return sendError(res, 400, 'Invalid workspace data')
    }

    await services.saveWorkspace(workspace)

    sendResponse(res, 200, {
      success: true,
      timestamp: Date.now()
    })
  } catch (error: any) {
    console.error('[Projects Route] Save workspace error:', error)
    sendError(res, 500, error.message || 'Failed to save workspace')
  }
})

/**
 * GET /api/projects/list
 * Get just the list of projects (convenience endpoint)
 *
 * Returns: Project[]
 */
router.get('/list', async (_req: Request, res: Response) => {
  try {
    const services = getServices()

    if (!services.getWorkspace) {
      return sendError(res, 503, 'Workspace service not available')
    }

    const workspace: Workspace = await services.getWorkspace()

    sendResponse(res, 200, {
      success: true,
      data: workspace.projects,
      timestamp: Date.now()
    })
  } catch (error: any) {
    sendError(res, 500, error.message || 'Failed to get projects')
  }
})

export default router

/**
 * Settings Routes
 *
 * HTTP endpoints for application settings, voice configuration, and CLI status.
 */

import { Router, Request, Response } from 'express'
import {
  ApiResponse,
  Settings,
  VoiceSettings
} from '../types'
import { getServices } from '../app'

const router = Router()

// =============================================================================
// Helper Functions
// =============================================================================

function sendResponse<T>(res: Response, statusCode: number, data: ApiResponse<T>): void {
  res.status(statusCode).json(data)
}

function sendError(res: Response, statusCode: number, error: string): void {
  sendResponse(res, statusCode, {
    success: false,
    error,
    timestamp: Date.now()
  })
}

// =============================================================================
// Application Settings Routes
// =============================================================================

/**
 * GET /api/settings
 * Get application settings
 *
 * Returns: Settings
 */
router.get('/', async (_req: Request, res: Response) => {
  try {
    const services = getServices()

    if (!services.getSettings) {
      return sendError(res, 503, 'Settings service not available')
    }

    const settings: Settings = await services.getSettings()

    sendResponse<Settings>(res, 200, {
      success: true,
      data: settings,
      timestamp: Date.now()
    })
  } catch (error: any) {
    console.error('[Settings Route] Get error:', error)
    sendError(res, 500, error.message || 'Failed to get settings')
  }
})

/**
 * PUT /api/settings
 * Save application settings
 *
 * Body: Settings
 */
router.put('/', async (req: Request, res: Response) => {
  try {
    const services = getServices()

    if (!services.saveSettings) {
      return sendError(res, 503, 'Settings service not available')
    }

    const settings: Settings = req.body

    // Basic validation
    if (!settings || typeof settings !== 'object') {
      return sendError(res, 400, 'Invalid settings data')
    }

    await services.saveSettings(settings)

    sendResponse(res, 200, {
      success: true,
      timestamp: Date.now()
    })
  } catch (error: any) {
    console.error('[Settings Route] Save error:', error)
    sendError(res, 500, error.message || 'Failed to save settings')
  }
})

/**
 * PATCH /api/settings
 * Partially update application settings
 *
 * Body: Partial<Settings>
 */
router.patch('/', async (req: Request, res: Response) => {
  try {
    const services = getServices()

    if (!services.getSettings || !services.saveSettings) {
      return sendError(res, 503, 'Settings service not available')
    }

    const updates: Partial<Settings> = req.body

    // Get current settings and merge
    const currentSettings = await services.getSettings()
    const newSettings = { ...currentSettings, ...updates }

    await services.saveSettings(newSettings)

    sendResponse<Settings>(res, 200, {
      success: true,
      data: newSettings,
      timestamp: Date.now()
    })
  } catch (error: any) {
    sendError(res, 500, error.message || 'Failed to update settings')
  }
})

// =============================================================================
// Voice Settings Routes
// =============================================================================

/**
 * GET /api/settings/voice
 * Get voice settings
 *
 * Returns: VoiceSettings
 */
router.get('/voice', async (_req: Request, res: Response) => {
  try {
    const services = getServices()

    if (!services.voiceGetSettings) {
      return sendError(res, 503, 'Voice service not available')
    }

    const settings: VoiceSettings = await services.voiceGetSettings()

    sendResponse<VoiceSettings>(res, 200, {
      success: true,
      data: settings,
      timestamp: Date.now()
    })
  } catch (error: any) {
    sendError(res, 500, error.message || 'Failed to get voice settings')
  }
})

/**
 * POST /api/settings/voice/speak
 * Speak text using TTS
 *
 * Body: { text: string }
 */
router.post('/voice/speak', async (req: Request, res: Response) => {
  try {
    const services = getServices()

    if (!services.voiceSpeak) {
      return sendError(res, 503, 'Voice service not available')
    }

    const { text } = req.body

    if (!text || typeof text !== 'string') {
      return sendError(res, 400, 'text is required and must be a string')
    }

    // Limit text length to prevent abuse
    if (text.length > 5000) {
      return sendError(res, 400, 'text must be 5000 characters or less')
    }

    const result = await services.voiceSpeak(text)

    sendResponse(res, result.success ? 200 : 500, {
      success: result.success,
      data: result.audioData ? { audioData: result.audioData } : undefined,
      error: result.error,
      timestamp: Date.now()
    })
  } catch (error: any) {
    sendError(res, 500, error.message || 'Failed to speak text')
  }
})

/**
 * POST /api/settings/voice/stop
 * Stop TTS playback
 */
router.post('/voice/stop', async (_req: Request, res: Response) => {
  try {
    const services = getServices()

    if (!services.voiceStopSpeaking) {
      return sendError(res, 503, 'Voice service not available')
    }

    const result = await services.voiceStopSpeaking()

    sendResponse(res, result.success ? 200 : 500, {
      success: result.success,
      timestamp: Date.now()
    })
  } catch (error: any) {
    sendError(res, 500, error.message || 'Failed to stop speaking')
  }
})

// =============================================================================
// CLI Status Routes
// =============================================================================

/**
 * GET /api/settings/cli/status
 * Get installation status of all CLI tools
 *
 * Returns: { claude, gemini, codex, opencode, aider }
 */
router.get('/cli/status', async (_req: Request, res: Response) => {
  try {
    const services = getServices()

    const status: Record<string, any> = {}

    // Check each CLI tool in parallel
    const checks = await Promise.allSettled([
      services.claudeCheck?.() ?? Promise.resolve({ installed: false }),
      services.geminiCheck?.() ?? Promise.resolve({ installed: false }),
      services.codexCheck?.() ?? Promise.resolve({ installed: false }),
      services.opencodeCheck?.() ?? Promise.resolve({ installed: false }),
      services.aiderCheck?.() ?? Promise.resolve({ installed: false })
    ])

    const cliNames = ['claude', 'gemini', 'codex', 'opencode', 'aider']

    checks.forEach((result, index) => {
      if (result.status === 'fulfilled') {
        status[cliNames[index]] = result.value
      } else {
        status[cliNames[index]] = { installed: false, error: result.reason?.message }
      }
    })

    sendResponse(res, 200, {
      success: true,
      data: status,
      timestamp: Date.now()
    })
  } catch (error: any) {
    sendError(res, 500, error.message || 'Failed to check CLI status')
  }
})

/**
 * GET /api/settings/cli/:tool
 * Get installation status of a specific CLI tool
 *
 * Params: tool - one of: claude, gemini, codex, opencode, aider
 */
router.get('/cli/:tool', async (req: Request, res: Response) => {
  try {
    const services = getServices()
    const { tool } = req.params

    const checkFunctions: Record<string, (() => Promise<any>) | undefined> = {
      claude: services.claudeCheck,
      gemini: services.geminiCheck,
      codex: services.codexCheck,
      opencode: services.opencodeCheck,
      aider: services.aiderCheck
    }

    const checkFn = checkFunctions[tool]
    if (!checkFn) {
      return sendError(res, 400, `Unknown tool: ${tool}. Valid tools: ${Object.keys(checkFunctions).join(', ')}`)
    }

    const result = await checkFn()

    sendResponse(res, 200, {
      success: true,
      data: result,
      timestamp: Date.now()
    })
  } catch (error: any) {
    sendError(res, 500, error.message || 'Failed to check CLI status')
  }
})

export default router

/**
 * Workspace Routes - /api/workspace, /api/settings, /api/sessions, /api/project endpoints
 */

import { Express, Request, Response } from 'express'
import { basename } from 'path'
import { validateProjectPath } from '../../mobile-security'
import { discoverSessions } from '../../session-discovery'
import { log } from '../utils'

export function setupWorkspaceRoutes(
  app: Express,
  getSessionStore: () => any
): void {
  // Reload workspace from disk
  app.post('/api/workspace/reload', async (_req: Request, res: Response) => {
    try {
      const sessionStore = getSessionStore()
      if (!sessionStore) {
        return res.status(500).json({ error: 'Session store not available' })
      }
      sessionStore.reloadFromDisk()
      const workspace = sessionStore.getWorkspace()
      res.json({ success: true, projectCount: workspace.projects?.length || 0 })
    } catch (error) {
      res.status(500).json({ error: String(error) })
    }
  })

  app.get('/api/workspace', async (_req: Request, res: Response) => {
    try {
      const sessionStore = getSessionStore()
      if (!sessionStore) {
        return res.status(500).json({ error: 'Session store not available' })
      }
      const workspace = sessionStore.getWorkspace()
      res.json(workspace)
    } catch (error) {
      res.status(500).json({ error: String(error) })
    }
  })

  app.put('/api/workspace', async (req: Request, res: Response) => {
    try {
      const sessionStore = getSessionStore()
      if (!sessionStore) {
        return res.status(500).json({ error: 'Session store not available' })
      }
      // Protect against overwriting populated workspace with empty one
      const incoming = req.body
      const incomingProjects = incoming?.projects?.length || 0
      if (incomingProjects === 0) {
        const current = sessionStore.getWorkspace()
        const currentProjects = current?.projects?.length || 0
        if (currentProjects > 0) {
          log('Rejected empty workspace save - current has projects', { currentProjects })
          return res.status(400).json({ error: 'Cannot overwrite populated workspace with empty one' })
        }
      }
      sessionStore.saveWorkspace(req.body)
      res.json({ success: true })
    } catch (error) {
      res.status(500).json({ error: String(error) })
    }
  })

  app.post('/api/workspace', async (req: Request, res: Response) => {
    try {
      const sessionStore = getSessionStore()
      if (!sessionStore) {
        return res.status(500).json({ error: 'Session store not available' })
      }
      // POST expects { workspace: {...} } wrapper format
      const incoming = req.body
      const workspace = incoming?.workspace
      if (!workspace) {
        return res.status(400).json({ error: 'Missing workspace field in request body' })
      }
      // Protect against overwriting populated workspace with empty one
      const incomingProjects = workspace?.projects?.length || 0
      if (incomingProjects === 0) {
        const current = sessionStore.getWorkspace()
        const currentProjects = current?.projects?.length || 0
        if (currentProjects > 0) {
          log('Rejected empty workspace save - current has projects', { currentProjects })
          return res.status(400).json({ error: 'Cannot overwrite populated workspace with empty one' })
        }
      }
      sessionStore.saveWorkspace(workspace)
      res.json({ success: true })
    } catch (error) {
      res.status(500).json({ error: String(error) })
    }
  })

  // Settings routes
  app.get('/api/settings', async (_req: Request, res: Response) => {
    try {
      const sessionStore = getSessionStore()
      if (!sessionStore) {
        return res.status(500).json({ error: 'Session store not available' })
      }
      const settings = sessionStore.getSettings()
      res.json(settings)
    } catch (error) {
      res.status(500).json({ error: String(error) })
    }
  })

  app.put('/api/settings', async (req: Request, res: Response) => {
    try {
      const sessionStore = getSessionStore()
      if (!sessionStore) {
        return res.status(500).json({ error: 'Session store not available' })
      }
      sessionStore.saveSettings(req.body)
      res.json({ success: true })
    } catch (error) {
      res.status(500).json({ error: String(error) })
    }
  })

  app.post('/api/settings', async (req: Request, res: Response) => {
    try {
      const sessionStore = getSessionStore()
      if (!sessionStore) {
        return res.status(500).json({ error: 'Session store not available' })
      }
      sessionStore.saveSettings(req.body)
      res.json({ success: true })
    } catch (error) {
      res.status(500).json({ error: String(error) })
    }
  })

  // Sessions discovery
  app.get('/api/sessions', async (req: Request, res: Response) => {
    try {
      const projectPath = req.query.path as string
      const backend = (req.query.backend as 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider') || 'claude'
      if (!projectPath) {
        return res.status(400).json({ error: 'Missing path' })
      }

      const pathValidation = validateProjectPath(projectPath)
      if (!pathValidation.valid) {
        return res.status(400).json({ error: pathValidation.error })
      }
      const safeProjectPath = pathValidation.normalizedPath!

      const sessions = await discoverSessions(safeProjectPath, backend)
      res.json({ sessions })
    } catch (error: any) {
      log('Sessions error', { error: String(error) })
      res.status(500).json({ error: error.message || String(error) })
    }
  })

  // Project add
  app.post('/api/project/add', async (req: Request, res: Response) => {
    try {
      const { path: projectPath } = req.body

      if (!projectPath || typeof projectPath !== 'string') {
        return res.status(400).json({ error: 'path is required and must be a string' })
      }

      const pathValidation = validateProjectPath(projectPath)
      if (!pathValidation.valid) {
        return res.status(400).json({ error: pathValidation.error })
      }
      const safeProjectPath = pathValidation.normalizedPath!

      const name = basename(safeProjectPath)

      log('Project add', { path: safeProjectPath, name })
      res.json({ path: safeProjectPath, name })
    } catch (error) {
      log('Project add error', { error: String(error) })
      res.status(500).json({ error: String(error) })
    }
  })
}

